#!/usr/bin/env node
/**
 * Bundle xterm.js + CanvasAddon together into a single IIFE.
 *
 * The CanvasAddon requires xterm.js internal service sharing via module
 * context. Loading them as separate UMD scripts breaks this. This script
 * bundles both from ES module source into a single IIFE where they share
 * the same module scope.
 *
 * Output: src/runtime/xterm-canvas.generated.ts
 */

import { buildSync } from 'esbuild';
import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const ENTRY = join(__dirname, '..', 'src', 'runtime', 'xterm-with-canvas-addon-entry.ts');
const OUTPUT_DIR = join(__dirname, '..', 'src', 'runtime');
const OUTPUT_TS = join(OUTPUT_DIR, 'xterm-canvas.generated.ts');

function bundle() {
  console.log('Bundling xterm.js + CanvasAddon as combined IIFE...');

  const result = buildSync({
    entryPoints: [ENTRY],
    bundle: true,
    format: 'iife',
    platform: 'browser',
    target: 'es2020',
    minify: true,
    write: false,
  });

  const code = result.outputFiles[0].text;
  console.log(`  Bundle size: ${code.length} bytes`);

  // Escape for template literal
  const escaped = code
    .replace(/\\/g, '\\\\')
    .replace(/`/g, '\\`')
    .replace(/\$\{/g, '\\${');

  const tsContent = `/* eslint-disable max-lines */
/**
 * Auto-generated xterm.js + CanvasAddon combined bundle.
 * DO NOT EDIT THIS FILE DIRECTLY.
 *
 * Both are bundled together so they share module context,
 * which is required for CanvasAddon to access xterm internals.
 *
 * Run "npm run build:xterm-canvas" to regenerate.
 */
export const XTERM_WITH_CANVAS_ADDON_JS = \`${escaped}\`
`;

  if (!existsSync(OUTPUT_DIR)) {
    mkdirSync(OUTPUT_DIR, { recursive: true });
  }

  writeFileSync(OUTPUT_TS, tsContent);
  console.log(`Generated: ${OUTPUT_TS}`);
}

bundle();
